import React from 'react';
import { ComposableMap, Geographies, Geography, Marker, Line } from "react-simple-maps";

const geoUrl = "https://cdn.jsdelivr.net/npm/world-atlas@2/countries-110m.json";

const AttackMap = ({ currentThreat }) => {
  // Coordinates mapping
  const locations = {
    'Russia': [100, 60],
    'China': [104, 35],
    'USA': [-95, 38],
    'Brazil': [-50, -10],
    'India': [78, 20] 
  };

  const originCoords = currentThreat && locations[currentThreat.origin_country] 
    ? locations[currentThreat.origin_country] 
    : locations['Russia'];

  const targetCoords = locations['India'];

  return (
    <div style={{ width: '100%', height: '100%', display: 'flex', justifyContent: 'center', alignItems: 'center', background: '#0b0f19', borderRadius: '8px' }}>
      <ComposableMap projectionConfig={{ scale: 140 }} style={{ width: "100%", height: "100%" }}>
        <Geographies geography={geoUrl}>
          {({ geographies }) =>
            geographies.map((geo) => (
              <Geography 
                key={geo.rsmKey} 
                geography={geo} 
                fill="#1e293b"      /* This makes the countries visible! (Light slate blue) */
                stroke="#3b82f6"    /* This gives them a glowing blue border */
                strokeWidth={0.8} 
                style={{
                  default: { outline: "none" },
                  hover: { fill: "#334155", outline: "none" },
                  pressed: { outline: "none" }
                }}
              />
            ))
          }
        </Geographies>

        {/* Attack Trajectory Line */}
        {currentThreat && currentThreat.attack_type !== 'Normal' && (
          <Line
            from={originCoords}
            to={targetCoords}
            stroke="#ef4444"
            strokeWidth={2}
            strokeLinecap="round"
            style={{ strokeDasharray: "4 4", animation: "dash 1s linear infinite" }}
          />
        )}

        {/* Attacker Node */}
        <Marker coordinates={originCoords}>
          <circle r={5} fill={currentThreat?.attack_type === 'Normal' ? '#00ff9d' : '#ef4444'} />
        </Marker>

        {/* Target Node (India) */}
        <Marker coordinates={targetCoords}>
          <circle r={6} fill="#00ff9d" />
          <circle r={12} fill="transparent" stroke="#00ff9d" strokeWidth={2} />
        </Marker>
      </ComposableMap>
    </div>
  );
};

export default AttackMap;
